import (
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"os"
	"strings"
)

// Middleware that prints the request content
func printRequestContent(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Log the request details
		log.Printf("Request Method: %s\n", r.Method)
		log.Printf("Request URL: %s\n", r.URL)
		log.Printf("Request Headers:\n%s\n", strings.Join(r.Header.StringLines(), "\n"))
		body, err := ioutil.ReadAll(r.Body)
		if err != nil {
			log.Printf("Error reading request body: %v\n", err)
			return
		}

		// Reset the request body to its original position
		r.Body = ioutil.NopCloser(strings.NewReader(string(body)))

		// Log the request body
		log.Printf("Request Body:\n%s\n", string(body))

		// Call the next middleware or handler in the chain
		next.ServeHTTP(w, r)
	})
}

func main() {
	// Create a new HTTP server and use the middleware
	http.HandleFunc("/", printRequestContent(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})))

	// Start the HTTP server on port 8080
	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Could not start server: %s", err)
	}
}
```

