    // File descriptor to connect to the process input/output
    int fd = open("somefile.txt", O_RDWR);

    if (fd == -1) {
        perror("open");
        return 1;
    }

    pid_t pid = fork();

    if (pid == -1) {
        perror("fork");
        return 1;
    } else if (pid == 0) { // Child process
        // Close other file descriptors in the child process
        close(STDIN_FILENO);
        close(STDOUT_FILENO);
        close(STDERR_FILENO);

        // Duplicate the file descriptor to stdin and stdout
        dup2(fd, STDIN_FILENO);
        dup2(fd, STDOUT_FILENO);
        dup2(fd, STDERR_FILENO);

